SELECT i.*, ste.site_nm AS site_nm, opt.opt_grp_nm AS opt_id_nm, ite.opt_nm AS parent_opt_item_nm, cd_ot.code_label AS opt_type_cd_nm FROM pd_prod_opt_item i LEFT JOIN sy_site ste ON ste.site_id = i.site_id LEFT JOIN pd_prod_opt opt ON opt.opt_id = i.opt_id LEFT JOIN pd_prod_opt_item ite ON ite.opt_item_id = i.parent_opt_item_id LEFT JOIN sy_code cd_ot ON cd_ot.code_grp = 'OPT_TYPE' AND cd_ot.code_value = i.opt_type_cd
ORDER BY i.opt_item_id ASC ORDER BY i.opt_item_id DESC ORDER BY i.opt_nm ASC ORDER BY i.opt_nm DESC ORDER BY i.reg_date ASC ORDER BY i.reg_date DESC ORDER BY i.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

SELECT i.*, ste.site_nm AS site_nm, opt.opt_grp_nm AS opt_id_nm, ite.opt_nm AS parent_opt_item_nm, cd_ot.code_label AS opt_type_cd_nm FROM pd_prod_opt_item i LEFT JOIN sy_site ste ON ste.site_id = i.site_id LEFT JOIN pd_prod_opt opt ON opt.opt_id = i.opt_id LEFT JOIN pd_prod_opt_item ite ON ite.opt_item_id = i.parent_opt_item_id LEFT JOIN sy_code cd_ot ON cd_ot.code_grp = 'OPT_TYPE' AND cd_ot.code_value = i.opt_type_cd
ORDER BY i.opt_item_id ASC ORDER BY i.opt_item_id DESC ORDER BY i.opt_nm ASC ORDER BY i.opt_nm DESC ORDER BY i.reg_date ASC ORDER BY i.reg_date DESC ORDER BY i.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

