UPDATE pd_prod_opt_item
site_id = #{siteId}, opt_id = #{optId}, opt_type_cd = #{optTypeCd}, opt_nm = #{optNm}, opt_val = #{optVal}, opt_val_code_id = #{optValCodeId}, parent_opt_item_id = #{parentOptItemId}, sort_ord = #{sortOrd}, use_yn = #{useYn}, upd_by = #{updBy}, upd_date = #{updDate},
WHERE opt_item_id = #{optItemId}
